The dead-simple fix you described is right. Here's what needs to happen in the gateway_restart handler — just replace the gracefulRestart call with:
typescriptcase 'gateway_restart': {
  const { execSync, spawn } = require('child_process');
  const root = path.resolve(__dirname, '..', '..', '..');

  // 1. Build
  console.log('[lifecycle] Running build before restart...');
  try {
    execSync('npm run build', { cwd: root, stdio: 'inherit', timeout: 180_000 });
  } catch {
    return { name, args, result: '❌ Build failed. Gateway NOT restarting.', error: true };
  }

  // 2. Spawn `prom gateway start` fully detached, then exit
  const child = spawn('prom', ['gateway', 'start'], {
    cwd: root,
    detached: true,
    stdio: 'ignore',
    shell: true,
  });
  child.unref();

  // 3. Exit current process after a short delay
  setTimeout(() => process.exit(0), 1000);

  return { name, args, result: '✅ Build succeeded. Gateway is restarting now...', error: false };
}
That's it — build, spawn prom gateway start fully detached with shell: true (so it finds the global prom command on Windows), unref, exit. No lifecycle.ts complexity needed.
